#include <bits/stdc++.h>
using namespace std;

bool canMakeBouquets(const vector<int>& bloomDay, int day, int bouquets, int adjacent) {
    int made = 0, run = 0;
    for (int bloom : bloomDay) {
        if (bloom <= day) {
            if (++run == adjacent) {
                ++made;
                run = 0;
            }
        } else run = 0;
    }
    return made >= bouquets;
}

int minimumDaysBrute(const vector<int>& bloomDay, int bouquets, int adjacent) {
    if (1LL * bouquets * adjacent > (long long)bloomDay.size()) return -1;
    int low = *min_element(bloomDay.begin(), bloomDay.end());
    int high = *max_element(bloomDay.begin(), bloomDay.end());
    for (int day = low; day <= high; ++day) {
        if (canMakeBouquets(bloomDay, day, bouquets, adjacent)) return day;
    }
    return -1;
}

int main() {
    vector<int> bloomDay = {1, 10, 3, 10, 2};
    cout << minimumDaysBrute(bloomDay, 3, 1) << "\n";
    return 0;
}

