#include <bits/stdc++.h>
using namespace std;

pair<int, int> peakGridBrute(const vector<vector<int>>& matrix) {
    int rows = matrix.size(), columns = matrix[0].size();
    const int directions[4][2] = {{-1, 0}, {1, 0}, {0, -1}, {0, 1}};
    for (int row = 0; row < rows; ++row) {
        for (int column = 0; column < columns; ++column) {
            bool peak = true;
            for (const auto& direction : directions) {
                int nextRow = row + direction[0], nextColumn = column + direction[1];
                if (nextRow >= 0 && nextRow < rows && nextColumn >= 0 && nextColumn < columns
                    && matrix[nextRow][nextColumn] >= matrix[row][column]) peak = false;
            }
            if (peak) return {row, column};
        }
    }
    return {-1, -1};
}

int main() {
    vector<vector<int>> matrix = {{1, 4}, {3, 2}};
    auto peak = peakGridBrute(matrix);
    cout << peak.first << " " << peak.second << "\n";
    return 0;
}

