#include <bits/stdc++.h>
using namespace std;

void rotateLeftRepeated(vector<int>& values, int distance) {
    if (values.empty()) return;
    distance %= values.size();
    while (distance--) {
        int first = values.front();
        for (int index = 1; index < (int)values.size(); ++index) values[index - 1] = values[index];
        values.back() = first;
    }
}

int main() {
    vector<int> values = {1, 2, 3, 4, 5};
    rotateLeftRepeated(values, 2);
    for (int value : values) cout << value << " ";
    cout << "\n";
