pair<int, int> frequencyExtremesBrute(const vector<int>& values) {
    vector<int> uniqueValues;
    for (int value : values) {
        if (find(uniqueValues.begin(), uniqueValues.end(), value) == uniqueValues.end()) uniqueValues.push_back(value);
    }
    int highValue = -1, lowValue = -1, highCount = -1, lowCount = INT_MAX;
    for (int candidate : uniqueValues) {
        int count = 0;
        for (int value : values) if (value == candidate) ++count;
        if (count > highCount) highCount = count, highValue = candidate;
        if (count < lowCount) lowCount = count, lowValue = candidate;
    }
    return {highValue, lowValue};
}

int main() {
