valid-parenthesis-string.code:
#include <bits/stdc++.h>
using namespace std;

bool validFrom(const string& text, int index, int balance) {
    if (balance < 0) return false;
    if (index == (int)text.size()) return balance == 0;
    if (text[index] == '(') return validFrom(text, index + 1, balance + 1);
    if (text[index] == ')') return validFrom(text, index + 1, balance - 1);
    return validFrom(text, index + 1, balance + 1)
        || validFrom(text, index + 1, balance - 1)
        || validFrom(text, index + 1, balance);
}

int main() {
    cout << boolalpha << validFrom("(*)", 0, 0) << "\n";
    return 0;
}

