long long candyWithTwoArrays(const vector<int>& ratings) {
    int size = ratings.size();
    vector<int> left(size, 1), right(size, 1);
    for (int index = 1; index < size; ++index) {
        if (ratings[index] > ratings[index - 1]) left[index] = left[index - 1] + 1;
    }
    for (int index = size - 2; index >= 0; --index) {
        if (ratings[index] > ratings[index + 1]) right[index] = right[index + 1] + 1;
    }
    long long total = 0;
    for (int index = 0; index < size; ++index) total += max(left[index], right[index]);
    return total;
}

