length-of-loop-in-ll.code:
#include <bits/stdc++.h>
using namespace std;

struct ListNode {
    int value;
    ListNode* next;
    explicit ListNode(int value) : value(value), next(nullptr) {}
};

int cycleLengthWithMap(ListNode* head) {
    unordered_map<ListNode*, int> firstSeen;
    int step = 0;
    while (head) {
        if (firstSeen.count(head)) return step - firstSeen[head];
        firstSeen[head] = step++;
        head = head->next;
    }
    return 0;
}

int main() {
    ListNode first(1), second(2), third(3), fourth(4);
    first.next = &second; second.next = &third; third.next = &fourth; fourth.next = &second;
    cout << cycleLengthWithMap(&first) << "\n";
    return 0;
}

