int lis(const vector<int>& values) {
    vector<int> length(values.size(), 1);
    for (int i = 0; i < (int)values.size(); ++i)
        for (int j = 0; j < i; ++j)
            if (values[j] < values[i]) length[i] = max(length[i], 1 + length[j]);
    return values.empty() ? 0 : *max_element(length.begin(), length.end());
