    for (int index = 0; index < (int)balloons.size(); ++index) {
        int left = index == 0 ? 1 : balloons[index - 1], right = index + 1 == (int)balloons.size() ? 1 : balloons[index + 1];
        vector<int> remaining = balloons;
        remaining.erase(remaining.begin() + index);
        answer = max(answer, left * balloons[index] * right + burst(remaining));
    }
    return answer;
}
int main() { cout << burst({3, 1, 5, 8}) << "\n"; return 0; }

#include <bits/stdc++.h>
using namespace std;

int solve(int left, int right, const vector<int>& values, vector<vector<int>>& memo) {
    if (left > right) return 0;
    int& answer = memo[left][right];
    if (answer != -1) return answer;
    answer = 0;
    for (int last = left; last <= right; ++last)
        answer = max(answer, values[left - 1] * values[last] * values[right + 1] + solve(left, last - 1, values, memo) + solve(last + 1, right, values, memo));
    return answer;
}
int main() { vector<int> values = {1, 3, 1, 5, 8, 1}; vector<vector<int>> memo(values.size(), vector<int>(values.size(), -1)); cout << solve(1, values.size() - 2, values, memo) << "\n"; return 0; }

