#include <bits/stdc++.h>
using namespace std;

struct Node { int value; Node* left; Node* right; explicit Node(int value): value(value), left(nullptr), right(nullptr) {} };
int depth(Node* root) {
    if (!root) return 0;
    queue<Node*> pending; pending.push(root); int levels = 0;
    while (!pending.empty()) {
        int width = pending.size(); ++levels;
        while (width--) { Node* node=pending.front(); pending.pop(); if(node->left) pending.push(node->left); if(node->right) pending.push(node->right); }
    }
    return levels;
}
int main() { Node* root=new Node(1); root->left=new Node(2); root->left->left=new Node(3); cout<<depth(root)<<"\n"; return 0; }

