#include <bits/stdc++.h>
using namespace std;

struct Node { int value; Node* left; Node* right; explicit Node(int value): value(value), left(nullptr), right(nullptr) {} };
Node* invert(Node* root) {
    if (!root) return root;
    queue<Node*> pending; pending.push(root);
    while (!pending.empty()) { Node* node=pending.front(); pending.pop(); swap(node->left,node->right); if(node->left) pending.push(node->left); if(node->right) pending.push(node->right); }
    return root;
}
int main() { Node* root=new Node(1); root->left=new Node(2); root->right=new Node(3); invert(root); cout<<root->left->value<<" "<<root->right->value<<"\n"; return 0; }

