    for(int row=0;row<rows;++row) for(int column=0;column<columns;++column) if(grid[row][column]=='1') {
        ++answer; queue<pair<int,int>> pending; pending.push({row,column}); grid[row][column]='0';
        while(!pending.empty()){pair<int,int> cell=pending.front(); int r=cell.first,c=cell.second; pending.pop(); for(int d=0;d<4;++d){int nr=r+move[d],nc=c+move[d+1]; if(nr>=0&&nr<rows&&nc>=0&&nc<columns&&grid[nr][nc]=='1'){grid[nr][nc]='0';pending.push({nr,nc});}}}
    }
    return answer;
}
