#include <bits/stdc++.h>
using namespace std;

struct Node { int value; vector<Node*> neighbors; explicit Node(int value):value(value){} };
Node* cloneGraph(Node* start) {
    if(!start) return nullptr; unordered_map<Node*,Node*> copy; copy[start]=new Node(start->value); queue<Node*> pending; pending.push(start);
    while(!pending.empty()){Node* node=pending.front();pending.pop();for(Node* next:node->neighbors){if(!copy.count(next)){copy[next]=new Node(next->value);pending.push(next);}copy[node]->neighbors.push_back(copy[next]);}}
    return copy[start];
}
